#!/usr/bin/env python3
"""
Generate 500 additional USMLE practice questions for the question bank.
Outputs TypeScript-compatible Question objects to append to questions.ts.
"""
import json, sys

# Start ID after the last existing question (last was 928)
START_ID = 929

questions = []

def q(id_num, step, subject, question_text, options, correct, en, zh, es, diff="Medium", hy_tag=None):
    """Add a question with all required fields"""
    obj = {
        "id": id_num,
        "step": step,
        "subject": subject,
        "question": question_text,
        "options": options,
        "correctAnswer": correct,
        "explanationEn": en,
        "explanationZh": zh,
        "explanationEs": es,
        "aiGenerated": True,
        "difficulty": diff,
    }
    if hy_tag:
        obj["highYieldTag"] = hy_tag
    questions.append(obj)

def to_ts():
    """Output as TypeScript array elements"""
    lines = []
    for q in questions:
        lines.append("  {")
        lines.append(f"    id: {q['id']}, step: '{q['step']}', subject: '{q['subject']}',")
        # Escape single quotes in question text
        qt = q['question'].replace("'", "\\'").replace("\n", " ")
        lines.append(f"    question: '{qt}',")
        opts = ", ".join(f"'{o.replace(chr(39), chr(92)+chr(39))}'" for o in q['options'])
        lines.append(f"    options: [{opts}],")
        lines.append(f"    correctAnswer: {q['correctAnswer']},")
        en = q['explanationEn'].replace("'", "\\'")
        zh = q['explanationZh'].replace("'", "\\'")
        es = q['explanationEs'].replace("'", "\\'")
        lines.append(f"    explanationEn: '{en}',")
        lines.append(f"    explanationZh: '{zh}',")
        lines.append(f"    explanationEs: '{es}',")
        lines.append(f"    aiGenerated: true,")
        lines.append(f"    difficulty: '{q['difficulty']}',")
        if q.get('highYieldTag'):
            lines.append(f"    highYieldTag: '{q['highYieldTag']}',")
        lines.append("  },")
    return "\n".join(lines)

